+#!/usr/bin/env node
+/**
+ * Simplified AgentDB Performance Benchmark
+ *
+ * Direct testing without full AgentDB wrapper
+ */
+
+import { performance } from 'perf_hooks';
+import { ReflexionMemory } from '../dist/controllers/ReflexionMemory.js';
